import { useState } from 'react';
import { Sliders } from 'lucide-react';

export function InteractiveInputSlider() {
  const [value, setValue] = useState(50);
  const min = 0;
  const max = 100;

  const handleSliderChange = (e) => {
    setValue(Number(e.target.value));
  };

  const handleInputChange = (e) => {
    const val = Number(e.target.value);
    if (val >= min && val <= max) {
      setValue(val);
    }
  };

  const percentage = ((value - min) / (max - min)) * 100;

  return (
    <div className="w-full max-w-md mx-auto border border-border bg-card text-card-foreground p-6 rounded-2xl shadow-xl">
      <div className="flex items-center justify-between mb-4">
        <div className="flex items-center gap-2">
          <Sliders className="h-5 w-5 text-primary" />
          <label className="text-sm font-bold tracking-tight text-foreground">Value Range Settings</label>
        </div>
        <span className={`text-xs px-2 py-0.5 rounded-full font-semibold uppercase tracking-wider ${
          value > 85 
            ? 'bg-rose-500/10 text-rose-500 border border-rose-500/20'
            : 'bg-primary/10 text-primary border border-primary/20'
        }`}>
          {value > 85 ? 'High Load' : 'Optimal'}
        </span>
      </div>

      <div className="flex items-center gap-6">
        {/* Range Slider Control */}
        <div className="relative flex-1">
          <input
            type="range"
            min={min}
            max={max}
            value={value}
            onChange={handleSliderChange}
            style={{
              background: `linear-gradient(to right, var(--primary) 0%, var(--primary) ${percentage}%, var(--muted) ${percentage}%, var(--muted) 100%)`
            }}
            className="w-full h-2 rounded-lg appearance-none cursor-pointer focus:outline-none focus:ring-2 focus:ring-primary/20 [&::-webkit-slider-thumb]:appearance-none [&::-webkit-slider-thumb]:h-5 [&::-webkit-slider-thumb]:w-5 [&::-webkit-slider-thumb]:rounded-full [&::-webkit-slider-thumb]:bg-background [&::-webkit-slider-thumb]:border-2 [&::-webkit-slider-thumb]:border-primary [&::-webkit-slider-thumb]:shadow-md [&::-webkit-slider-thumb]:transition-all [&::-webkit-slider-thumb]:hover:scale-110"
          />
        </div>

        {/* Numeric Input Display */}
        <div className="relative w-20">
          <input
            type="number"
            min={min}
            max={max}
            value={value}
            onChange={handleInputChange}
            className="w-full text-center py-2 px-3 text-sm border border-border rounded-xl bg-background focus:outline-none focus:ring-2 focus:ring-primary/20 font-mono font-bold text-foreground"
          />
        </div>
      </div>

      <div className="mt-4 flex items-center justify-between text-xs text-muted-foreground font-mono">
        <span>Min: {min}</span>
        <span>Max: {max}</span>
      </div>
    </div>
  );
}

