import { useState } from 'react';
import { ChevronDown, HelpCircle } from 'lucide-react';

export function FAQAccordion() {
  const [activeIndex, setActiveIndex] = useState(null);

  const faqs = [
    {
      question: "How do I connect OpenBlocks to Cursor IDE or Claude Desktop?",
      answer: "Open your client configurations settings and register OpenBlocks as an stdio MCP server. Check the README file for copy-paste-ready JSON configs."
    },
    {
      question: "Can I register custom styling templates or frameworks?",
      answer: "Absolutely! OpenBlocks supports any client framework aliasing. Simply use the add_component tool or add it to database seed files."
    },
    {
      question: "Is there a limit to components stored in the database?",
      answer: "No. The backend uses SQLite, meaning it scales comfortably to thousands of components with indexing and search remaining fast."
    }
  ];

  const toggleIndex = (idx) => {
    setActiveIndex(activeIndex === idx ? null : idx);
  };

  return (
    <div className="w-full max-w-2xl mx-auto border border-border bg-card text-card-foreground p-6 rounded-2xl shadow-xl">
      <div className="flex items-center gap-2 mb-6 border-b border-border pb-4">
        <HelpCircle className="h-5 w-5 text-primary" />
        <h3 className="text-lg font-bold tracking-tight text-foreground">Frequently Asked Questions</h3>
      </div>

      <div className="space-y-4">
        {faqs.map((faq, idx) => {
          const isOpen = activeIndex === idx;
          return (
            <div 
              key={idx} 
              className="border border-border rounded-xl overflow-hidden transition-all duration-200 bg-muted/10"
            >
              <button
                onClick={() => toggleIndex(idx)}
                className="w-full flex items-center justify-between p-4 text-left font-semibold text-sm hover:bg-muted/40 transition-colors text-foreground"
              >
                <span>{faq.question}</span>
                <ChevronDown className={`h-4.5 w-4.5 text-muted-foreground transition-transform duration-200 ${isOpen ? 'rotate-180' : ''}`} />
              </button>

              <div 
                style={{ height: isOpen ? 'auto' : '0px' }}
                className="overflow-hidden transition-all duration-300 ease-in-out bg-background/50 border-t border-border/40"
              >
                <div className="p-4 text-sm leading-relaxed text-muted-foreground">
                  {faq.answer}
                </div>
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
}
